const cfg = $input.first().json;
const now = Date.now();
const items = [];

const addCases = (scenario, count, extra = {}) => {
  for (let i = 0; i < Number(count || 0); i++) {
    items.push({
      json: {
        webhook_url: cfg.webhook_url,
        mock_base_url: cfg.mock_base_url,
        channel: cfg.channel || 'EMAIL',
        scenario,
        transaction_id: `tx-${scenario}-${now}-${String(i + 1).padStart(3, '0')}`,
        amount: 12000,
        account_balance: 50000,
        payment_status: 'APPROVED',
        force_insufficient: false,
        force_bank_reject: false,
        force_recaudo_reject: false,
        force_tullave_reject: false,
        force_dian_reject: false,
        force_notify_reject: false,
        delay_ms: 0,
        jitter_ms: 0,
        ...extra,
      },
    });
  }
};

addCases('success', cfg.success_count);
addCases('payment_rejected', cfg.payment_rejected_count, {
  payment_status: 'REJECTED',
});
addCases('insufficient_balance', cfg.insufficient_balance_count, {
  account_balance: 5000,
});
addCases('insufficient_forced', cfg.insufficient_forced_count, {
  force_insufficient: true,
});
addCases('bank_reject', cfg.bank_reject_count, {
  force_bank_reject: true,
});
addCases('recaudo_reject', cfg.recaudo_reject_count, {
  force_recaudo_reject: true,
});
addCases('tullave_reject', cfg.tullave_reject_count, {
  force_tullave_reject: true,
});
addCases('dian_reject', cfg.dian_reject_count, {
  force_dian_reject: true,
});
addCases('notify_reject', cfg.notify_reject_count, {
  force_notify_reject: true,
});
addCases('latency_simulated', cfg.latency_count, {
  delay_ms: Number(cfg.delay_ms || 250),
  jitter_ms: Number(cfg.jitter_ms || 75),
});

return items;

const rows = $input.all().map(item => item.json);
const byStatus = {};
const byReason = {};

for (const row of rows) {
  const status = row.status || 'unknown';
  const reason = row.fail_reason || '(none)';
  byStatus[status] = (byStatus[status] || 0) + 1;
  byReason[reason] = (byReason[reason] || 0) + 1;
}

return [
  {
    json: {
      total_requests: rows.length,
      by_status: byStatus,
      by_fail_reason: byReason,
      sample: rows.slice(0, 5),
    },
  },
];
